public enum EntityIconColorProvider {
    public static func iconColor(
        domain: Domain,
        state: String,
        colorMode: String?,
        rgbColor: [Int]?,
        hsColor: [Double]?
    ) -> Color {
        guard Domain.activeStates.map(\.rawValue).contains(state) else {
            if Domain.problemStates.map(\.rawValue).contains(state) {
                return .red
            } else {
                return .gray
            }
        }

        // Check color_mode first if available to prioritize the correct attribute
        if let colorMode {
            switch colorMode {
            case "rgb", "rgbw", "rgbww":
                if let rgb = rgbColor, rgb.count == 3 {
                    return Color(
                        red: Double(rgb[0]) / 255.0,
                        green: Double(rgb[1]) / 255.0,
                        blue: Double(rgb[2]) / 255.0
                    )
                }
            case "hs":
                if let hs = hsColor, hs.count == 2 {
                    return Color(hue: hs[0] / 360.0, saturation: hs[1] / 100.0, brightness: 1.0)
                }
            case "xy", "color_temp":
                // Home Assistant usually provides rgb_color approximation for xy and color_temp
                if let rgb = rgbColor, rgb.count == 3 {
                    return Color(
                        red: Double(rgb[0]) / 255.0,
                        green: Double(rgb[1]) / 255.0,
                        blue: Double(rgb[2]) / 255.0
                    )
                }
            default:
                break
            }
        }

        // Fallback or if color_mode is missing
        if let rgb = rgbColor, rgb.count == 3 {
            return Color(
                red: Double(rgb[0]) / 255.0,
                green: Double(rgb[1]) / 255.0,
                blue: Double(rgb[2]) / 255.0
            )
        }

        if let hs = hsColor, hs.count == 2 {
            return Color(hue: hs[0] / 360.0, saturation: hs[1] / 100.0, brightness: 1.0)
        }

        return domain.accentColor
    }
}

public extension Domain {
    var accentColor: Color {
        switch self {
        case .light:
            Color.Domain.light
        case .switch:
            Color.Domain.switch
        case .fan:
            Color.Domain.fan
        case .cover:
            Color.Domain.cover
        default:
            Color.haPrimary
        }
    }
}

import CustomDump

public struct IndexedCubeFace: Codable, Hashable, Sendable {
  public var index: LatticePoint
  public var side: CubeFace.Side

  public init(
    index: LatticePoint,
    side: CubeFace.Side
  ) {
    self.index = index
    self.side = side
  }

  public func isTouching(_ other: IndexedCubeFace) -> Bool {
    guard self != other else { return false }

    let otherEdges = other.edges

    return self.edges
      .contains { edge in
        otherEdges.contains { otherEdge in
          edge.isTouching(edge: otherEdge)
        }
      }
  }

  public static let cubeIndices = LatticePoint.cubeIndices.flatMap { index in
    CubeFace.Side.allCases.map { side in
      Self(index: index, side: side)
    }
  }

  private var edges: [Edge] {
    var result: [Edge.Point] = []

    switch self.side {
    case .top:
      result.append(contentsOf: cubeTopFaceVertices.map { $0 + .init(self.index) })
    case .left:
      result.append(contentsOf: cubeLeftFaceVertices.map { $0 + .init(self.index) })
    case .right:
      result.append(contentsOf: cubeRightFaceVertices.map { $0 + .init(self.index) })
    }

    let loop = result + [result[0]]
    return zip(loop, loop.dropFirst())
      .map(Edge.init(start:end:))
  }
}

extension IndexedCubeFace: CustomDumpStringConvertible {
  public var customDumpDescription: String {
    "\(self.index.customDumpDescription)@\(self.side)"
  }
}

private struct Edge: Equatable {
  struct Point: Equatable {
    let x, y, z: Int

    static func + (lhs: Self, rhs: Self) -> Self {
      Self(x: lhs.x + rhs.x, y: lhs.y + rhs.y, z: lhs.z + rhs.z)
    }
  }

  let start: Point
  let end: Point

  func isTouching(edge other: Edge) -> Bool {
    self.start == other.start
      || self.start == other.end
      || self.end == other.start
      || self.end == other.end
  }
}

extension Edge.Point {
  init(_ index: LatticePoint) {
    self.init(x: index.x.rawValue, y: index.y.rawValue, z: index.z.rawValue)
  }
}

private let cubeTopFaceVertices = [
  Edge.Point(x: 0, y: 1, z: 1),
  Edge.Point(x: 0, y: 1, z: 0),
  Edge.Point(x: 1, y: 1, z: 0),
  Edge.Point(x: 1, y: 1, z: 1),
]

private let cubeLeftFaceVertices = [
  Edge.Point(x: 0, y: 1, z: 1),
  Edge.Point(x: 1, y: 1, z: 1),
  Edge.Point(x: 1, y: 0, z: 1),
  Edge.Point(x: 0, y: 0, z: 1),
]

private let cubeRightFaceVertices = [
  Edge.Point(x: 1, y: 1, z: 1),
  Edge.Point(x: 1, y: 1, z: 0),
  Edge.Point(x: 1, y: 0, z: 0),
  Edge.Point(x: 1, y: 0, z: 1),
]

import CustomDump

public struct LatticePoint: Codable, Hashable, Sendable {
  public enum Index: Int, CaseIterable, Codable, Comparable, Sendable {
    case zero = 0
    case one = 1
    case two = 2

    public static func < (lhs: Self, rhs: Self) -> Bool {
      lhs.rawValue < rhs.rawValue
    }
  }

  public var x: Index
  public var y: Index
  public var z: Index

  public init(x: Index, y: Index, z: Index) {
    self.x = x
    self.y = y
    self.z = z
  }

  public static let zero = Self(x: Index.zero, y: .zero, z: .zero)

  public static let cubeIndices = Index.allCases.flatMap { xIndex in
    Index.allCases.flatMap { yIndex in
      Index.allCases.map { zIndex in
        LatticePoint(x: xIndex, y: yIndex, z: zIndex)
      }
    }
  }
}

extension LatticePoint: CustomDumpStringConvertible {
  public var customDumpDescription: String {
    "\(self.x.rawValue).\(self.y.rawValue).\(self.z.rawValue)"
  }
}

extension Three {
  public subscript(offset: LatticePoint.Index) -> Element {
    get {
      switch offset {
      case .zero: return self.first
      case .one: return self.second
      case .two: return self.third
      }
    }
    set {
      switch offset {
      case .zero: self.first = newValue
      case .one: self.second = newValue
      case .two: self.third = newValue
      }
    }
  }
}

extension Three {
  public subscript<A>(index: LatticePoint) -> A where Element == Three<Three<A>> {
    get { self[index.x][index.y][index.z] }
    set { self[index.x][index.y][index.z] = newValue }
  }
}

extension LatticePoint {
  public init?(x: Int, y: Int, z: Int) {
    guard
      let x = Index(rawValue: x),
      let y = Index(rawValue: y),
      let z = Index(rawValue: z)
    else { return nil }
    self.init(x: x, y: y, z: z)
  }

  public static func + (lhs: Self, rhs: Self) -> Self? {
    Self(
      x: lhs.x.rawValue + rhs.x.rawValue,
      y: lhs.y.rawValue + rhs.y.rawValue,
      z: lhs.z.rawValue + rhs.z.rawValue
    )
  }
}

